#include <iostream>
using namespace std;
unsigned long long int fun(unsigned int n)
{
unsigned long long int x = 0;
unsigned long long int y = 1;
for (unsigned int j = 2; j <= n; ++j){
if (j % 2 == 0) x += y;
else y += x;
}
if(n % 2 == 0) return x;
else return y;
}
